#include <bits/stdc++.h>
using namespace std;
#define int long long
const int maxn=1e5+5;
int n,sum,ans=INT_MIN,vis[maxn];
struct node{
	int v,w;
};
vector<node> e[maxn];
void dfs(int x,int vv){
	if(vis[x]){
		return;
	}
	vis[x]=1;
	for(auto s:e[x]){
		dfs(s.v,vv+s.w);
	}
	ans=max(ans,vv);
}
signed main(){
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n;
	for(int i=1;i<n;i++){
		int x,y,z;
		cin>>x>>y>>z;
		e[x].push_back({y,z});
		e[y].push_back({x,z});
		sum+=z;
	}
	dfs(1,0);
	cout<<sum*2-ans;
	return 0;
}
